import {
  Button,
  ButtonVariant,
  Content,
  ContentVariants,
  InputGroup,
  TextInput,
  Toolbar,
  ToolbarContent,
  ToolbarItem,
  ToolbarToggleGroup,
} from '@patternfly/react-core';
import { EllipsisVIcon, RedoIcon, SearchIcon } from '@patternfly/react-icons';
import cronstrue from 'cronstrue';
import React from 'react';

type Props = {
  filterValue: string;
  backupSchedule: string | undefined;
  onFilterChange: (value: string) => void;
  onFilterApply: () => void;
  onFilterClear: () => void;
  onRestoreClick: () => void;
};

export class BackupsListToolbar extends React.PureComponent<Props> {
  private handleKeyDown(event: React.KeyboardEvent): void {
    switch (event.key) {
      case 'Enter':
        this.props.onFilterApply();
        break;
      case 'Escape':
        this.props.onFilterClear();
        break;
    }
  }

  public render(): React.ReactElement {
    const { filterValue, backupSchedule, onFilterChange, onFilterApply, onRestoreClick } =
      this.props;

    let scheduleLabel: string;
    if (backupSchedule) {
      try {
        scheduleLabel = `Backup schedule: ${cronstrue.toString(backupSchedule)}`;
      } catch {
        scheduleLabel = `Backup schedule: ${backupSchedule}`;
      }
    } else {
      scheduleLabel = 'No backup schedule configured';
    }

    return (
      <Toolbar id="backups-view-toolbar" data-testid="backups-view-toolbar">
        <ToolbarContent>
          <ToolbarItem>
            <InputGroup>
              <TextInput
                name="backups-filter-input"
                id="backups-filter-input"
                type="search"
                aria-label="Filter backups"
                placeholder="Search"
                value={filterValue}
                onChange={(_event, value) => onFilterChange(value)}
                onKeyDown={event => this.handleKeyDown(event)}
                data-testid="backups-filter-input"
              />
              <Button
                variant="control"
                aria-label="Filter backups"
                onClick={() => onFilterApply()}
                data-testid="backups-filter-button"
              >
                <SearchIcon />
              </Button>
            </InputGroup>
          </ToolbarItem>
          <ToolbarToggleGroup
            breakpoint="md"
            toggleIcon={<EllipsisVIcon />}
            data-testid="backups-toolbar-toggle-group"
            style={{ flexGrow: 1 }}
          >
            <ToolbarItem
              align={{
                md: 'alignEnd',
                lg: 'alignEnd',
                xl: 'alignEnd',
                '2xl': 'alignEnd',
              }}
            >
              <Button
                icon={<RedoIcon />}
                iconPosition="left"
                variant={ButtonVariant.link}
                onClick={() => onRestoreClick()}
                data-testid="restore-from-backup-button"
              >
                Restore Workspace
              </Button>
            </ToolbarItem>
          </ToolbarToggleGroup>
        </ToolbarContent>
        <ToolbarContent data-testid="next-backup-info">
          <ToolbarItem align={{ default: 'alignEnd' }}>
            <Content
              id="next-scheduled-backup-label"
              component={ContentVariants.small}
              data-testid="next-scheduled-backup"
            >
              {scheduleLabel}
            </Content>
          </ToolbarItem>
        </ToolbarContent>
      </Toolbar>
    );
  }
}

export default BackupsListToolbar;
